import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { ShoppingCart, Menu, X, Phone } from 'lucide-react';
import { useCart } from '../lib/CartContext';
import './Navbar.css';

const NAV_LINKS = [
  { to: '/',            label: 'Home'        },
  { to: '/menu',        label: 'Menu'        },
  { to: '/gallery',     label: 'Gallery'     },
  { to: '/reservation', label: 'Reserve'     },
  { to: '/about',       label: 'Our Story'   },
  { to: '/reviews',     label: 'Reviews'     },
];

export default function Navbar({ onCartOpen }) {
  const { totalItems } = useCart();
  const [scrolled, setScrolled]   = useState(false);
  const [mobileOpen, setMobile]   = useState(false);
  const { pathname }              = useLocation();

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 40);
    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  useEffect(() => { setMobile(false); }, [pathname]);

  const isHome = pathname === '/';

  return (
    <>
      <nav className={`navbar ${scrolled || !isHome ? 'navbar--solid' : ''}`}>
        <div className="navbar__inner">
          {/* Logo */}
          <Link to="/" className="navbar__logo">
            <span className="navbar__logo-icon">🍜</span>
            <span className="navbar__logo-text">
              <span className="navbar__logo-main">BurmeseBites</span>
              <span className="navbar__logo-sub">Authentic Myanmar Cuisine</span>
            </span>
          </Link>

          {/* Desktop links */}
          <ul className="navbar__links">
            {NAV_LINKS.map(({ to, label }) => (
              <li key={to}>
                <Link
                  to={to}
                  className={`navbar__link ${pathname === to ? 'navbar__link--active' : ''}`}
                >
                  {label}
                </Link>
              </li>
            ))}
          </ul>

          {/* Right actions */}
          <div className="navbar__actions">
            <a href="tel:+66012345678" className="navbar__phone">
              <Phone size={14} />
              <span>+66 01 234 5678</span>
            </a>
            <button className="navbar__cart" onClick={onCartOpen} aria-label="Open cart">
              <ShoppingCart size={20} />
              {totalItems > 0 && (
                <span className="navbar__cart-badge">{totalItems}</span>
              )}
            </button>
            <button
              className="navbar__mobile-toggle"
              onClick={() => setMobile(v => !v)}
              aria-label="Toggle menu"
            >
              {mobileOpen ? <X size={22} /> : <Menu size={22} />}
            </button>
          </div>
        </div>
      </nav>

      {/* Mobile drawer */}
      <div className={`mobile-drawer ${mobileOpen ? 'mobile-drawer--open' : ''}`}>
        <ul className="mobile-drawer__links">
          {NAV_LINKS.map(({ to, label }) => (
            <li key={to}>
              <Link
                to={to}
                className={`mobile-drawer__link ${pathname === to ? 'mobile-drawer__link--active' : ''}`}
              >
                {label}
              </Link>
            </li>
          ))}
          <li>
            <button className="btn btn-primary mobile-drawer__order" onClick={onCartOpen}>
              Order Online
            </button>
          </li>
        </ul>
      </div>
      {mobileOpen && <div className="mobile-overlay" onClick={() => setMobile(false)} />}
    </>
  );
}
